mapper.delete:
DELETE FROM t_account
WHERE user_id = #{userId}
  AND currency = #{currency}

mapper.select:
SELECT COUNT(1)
FROM t_account
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_deposit
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_deposit
WHERE wallet_tx_id = #{walletTxId}

SELECT status
FROM t_deposit
